+/// Given a list of argument uses, update the access info for the argument.
+static void collectArgumentUsesPerBlock(Argument &Arg, Function &F) {
+  ArgumentUses Uses = getArgumentUses(Arg);
+  if (Uses.Uses.empty())
+    return;
+
+  const DataLayout &DL = F.getParent()->getDataLayout();
+
+  struct UseInfo {
+    ArgumentAccessInfo Access;
+    bool IsEntryBlock;
+  };
+  DenseMap<BasicBlock *, UseInfo> UseInfoByBlock;
+
+  auto UpdateUseInfo = [&](Instruction *I, ArgumentAccessInfo &&Access) {
+    if (!Access.hasAccess())
+      return false;
+
+    BasicBlock *BB = I->getParent();
+    auto It = UseInfoByBlock.find(BB);
+    if (It == UseInfoByBlock.end())
+      UseInfoByBlock.insert(
+          {BB, {std::move(Access), BB == &F.getEntryBlock()}});
+    else
+      It->second.Access.unionWith(std::move(Access));
+    return !UseInfoByBlock.lookup(BB).Access.isReadOnly();
+  };
+
+  BasicBlock &EntryBB = F.getEntryBlock();
+  for (const ArgumentUse &ArgUse : Uses.Uses) {
+    User *U = ArgUse.U->getUser();
+    // Add GEP uses to worklist.
+    // If the GEP is not a constant GEP, set the ArgumentUse::Offset to nullopt.
+    if (auto *GEP = dyn_cast<GEPOperator>(U)) {
+      std::optional<int64_t> NewOffset = std::nullopt;
+      if (ArgUse.Offset) {
+        APInt Offset(DL.getPointerSizeInBits(GEP->getPointerAddressSpace()), 0);
+        if (GEP->accumulateConstantOffset(DL, Offset))
+          NewOffset = *ArgUse.Offset + Offset.getSExtValue();
+      }
+      for (Use &U : GEP->uses())
+        Worklist.push_back({&U, NewOffset});
+      continue;
+    }
+
+    auto *I = cast<Instruction>(U);
+    bool HasWrite = UpdateUseInfo(I, getArgumentAccessInfo(I, ArgUse, DL));
+
+    Result.HasAnyWrite |= HasWrite;
+
+    if (HasWrite && I->getParent() != &EntryBB)
+      UseInfoByBlock.lookup(I->getParent()).IsEntryBlock = false;
+  }
+
+  if (Uses.HasAnyWrite) {
+    // For each block that has a write, if it is not the entry block, we need
+    // to check if it is dominated by all other blocks that have a write.
+    for (auto &It : UseInfoByBlock) {
+      if (It.second.Access.isReadOnly() || It.second.IsEntryBlock)
+        continue;
+      for (auto &It2 : UseInfoByBlock) {
+        if (&It == &It2 || It2.second.Access.isReadOnly())
+          continue;
+        if (!DT.dominates(It2.first, It.first)) {
+          It.second.IsEntryBlock = false;
+          break;
+        }
+      }
+    }
+  }
+
+  for (auto &It : UseInfoByBlock) {
+    if (It.second.Access.isReadOnly() || !It.second.IsEntryBlock)
+      continue;
+    for (const ConstantRange &CR : It.second.Access.getRanges())
+      Arg.addAttr(Attribute::getWithConstantRangeList(F.getContext(),
+                                                      Attribute::Initializes,
+                                                      {CR}));
+  }
+}
